from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.children = defaultdict(TrieNode)

class Solution:
    def search(self, root, word):
        for ch in word:
            if ch not in root.children:
                return False
            root = root.children[ch]
        return True

