#include <bits/stdc++.h>

using namespace std;

class TrieNode {
public:
    unordered_map<char, TrieNode*> children;
};

class Solution {
public:
bool search(TrieNode* root, string& word) {
    for (char ch : word) {
        if (root->children.find(ch) == root->children.end()) {
            return false;
        }
        root = root->children[ch];
    }
    return true;
}
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    // Create a Trie
    string word_list[] = {"apple", "banana", "orange"};
    TrieNode* root = new TrieNode();
    for (string word : word_list) {
        TrieNode* node = root;
        for (char ch : word) {
            if (node->children.find(ch) == node->children.end()) {
                node->children[ch] = new TrieNode();
            }
            node = node->children[ch];
        }
    }

    // Test the search function
    Solution solution;
    cout << solution.search(root, "apple") << endl;  // Output: 1
    cout << solution.search(root, "banana") << endl;  // Output: 1
    cout << solution.search(root, "grape") << endl;  // Output: 0

    return 0;
}
